2	
3	import { use, useEffect, useState } from "react";
4	import { useRouter } from "next/navigation";
5	import Link from "next/link";
6	import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
7	import { apiFetch, getToken } from "@/lib/api-client";
8	import { Header } from "@/components/Header";
9	import { StatusColumn } from "@/components/StatusColumn";
10	import { TaskDetail } from "@/components/TaskDetail";
11	import type { ApiProjectDetail, ApiTask, TaskStatus } from "@/types";
12	import { STATUS_ORDER } from "@/types";
13	
14	type PageProps = { params: Promise<{ id: string }> };
15	
16	export default function ProjectPage({ params }: PageProps) {
17	  const router = useRouter();
18	  const { id } = use(params);
19	  const queryClient = useQueryClient();
20	
21	  const [activeTask, setActiveTask] = useState<ApiTask | null>(null);
22	  const [newTitle, setNewTitle] = useState("");
23	  const [newColumn, setNewColumn] = useState<TaskStatus>("todo");
24	  const [error, setError] = useState<string | null>(null);
25	
26	  useEffect(() => {
27	    if (!getToken()) router.replace("/login");
28	  }, [router]);
29	
30	  const { data, isLoading, error: queryError } = useQuery({
31	    queryKey: ["project", id],
32	    queryFn: () => apiFetch<{ project: ApiProjectDetail }>(`/api/projects/${id}`),
33	  });
34	
35	  const createTask = useMutation({
36	    mutationFn: (input: { title: string; status: TaskStatus }) =>
37	      apiFetch<{ task: ApiTask }>(`/api/projects/${id}/tasks`, {
38	        method: "POST",
39	        body: JSON.stringify(input),
40	      }),
41	    onSuccess: () => {
42	      setNewTitle("");
43	      queryClient.invalidateQueries({ queryKey: ["project", id] });
44	    },
45	    onError: (err) => setError(err instanceof Error ? err.message : "create failed"),
46	  });
47	
48	  const project = data?.project;
49	  const tasksByStatus: Record<TaskStatus, ApiTask[]> = {
50	    todo: [],
51	    in_progress: [],
52	    review: [],
53	    done: [],
54	  };
55	  if (project) {
56	    for (const t of project.tasks) {
57	      tasksByStatus[t.status].push(t);
58	    }
59	  }
60	
61	  return (
62	    <div className="min-h-screen">
63	      <Header />
64	
65	      <main className="max-w-7xl mx-auto px-6 py-8">
66	        <Link
67	          href="/dashboard"
68	          className="text-sm text-muted hover:text-white"
69	        >
70	          ← all projects
71	        </Link>
72	
73	        {isLoading && <p className="text-muted text-sm mt-6">loading…</p>}
74	        {queryError && (
75	          <p className="text-sm text-red-400 mt-6">
76	            {queryError instanceof Error ? queryError.message : "failed to load"}
77	          </p>
78	        )}
79	
80	        {project && (
81	          <>
82	            <div className="flex items-start justify-between mt-4 mb-8">
83	              <div>
84	                <h1 className="text-2xl font-semibold">{project.name}</h1>
85	                {project.description && (
86	                  <p className="text-sm text-muted mt-1 max-w-2xl">
87	                    {project.description}
88	                  </p>
89	                )}
90	                <p className="text-xs text-muted mt-2">
91	                  owner: {project.owner.name} · {project.memberships.length} members
92	                </p>
93	              </div>
94	            </div>
95	
96	            <section className="bg-surface border border-border rounded-lg p-4 mb-6">
97	              <h2 className="text-sm font-medium mb-3">add a task</h2>
98	              <form
99	                onSubmit={(e) => {
100	                  e.preventDefault();
101	                  if (!newTitle.trim()) return;
102	                  setError(null);
103	                  createTask.mutate({ title: newTitle.trim(), status: newColumn });
104	                }}
105	                className="flex gap-2"
106	              >
107	                <input
108	                  type="text"
109	                  value={newTitle}
110	                  onChange={(e) => setNewTitle(e.target.value)}
111	                  placeholder="task title"
112	                  className="flex-1 rounded-md bg-bg border border-border px-3 py-2 text-sm focus:border-accent focus:outline-none"
113	                />
114	                <select
115	                  value={newColumn}
116	                  onChange={(e) => setNewColumn(e.target.value as TaskStatus)}
117	                  className="rounded-md bg-bg border border-border px-3 py-2 text-sm focus:border-accent focus:outline-none"
118	                >
119	                  {STATUS_ORDER.map((s) => (
120	                    <option key={s} value={s}>
121	                      {s}
122	                    </option>
123	                  ))}
124	                </select>
125	                <button
126	                  type="submit"
127	                  disabled={createTask.isPending}
128	                  className="bg-accent hover:bg-indigo-500 text-white text-sm font-medium rounded-md px-4 disabled:opacity-50"
129	                >
