  triggeredById: string;
  status: "queued" | "running" | "succeeded" | "failed";
  totalTasks: number;
  successCount: number;
  failureCount: number;
  errors: unknown;
  attempts: number;
  lastProcessedTaskId: string | null;
  heartbeatAt: Date | null;
  bullJobId: string | null;
  startedAt: Date | null;
  finishedAt: Date | null;
  createdAt: Date;
};

const tasks: Task[] = [];
const jobs = new Map<string, ExportJob>();

function makeTask(i: number, projectId: string): Task {
  return {
    id: `task_${String(i).padStart(4, "0")}`,
    projectId,
    title: `task ${i}`,
    description: null,
    status: "todo",
    createdAt: new Date("2026-05-13T10:00:00Z"),
    updatedAt: new Date("2026-05-13T10:00:00Z"),
    assignee: null,
  };
}

function seedTasks(projectId: string, n: number) {
  tasks.length = 0;
  for (let i = 0; i < n; i++) tasks.push(makeTask(i, projectId));
}

function makeJob(id: string, projectId: string): ExportJob {
  const j: ExportJob = {
    id,
    projectId,
    triggeredById: "u_1",
    status: "queued",
    totalTasks: 0,
    successCount: 0,
    failureCount: 0,
    errors: null,
    attempts: 0,
    lastProcessedTaskId: null,
    heartbeatAt: null,
    bullJobId: null,
    startedAt: null,
